2 Practice 2: Missingness audit
Goal: Check missing data patterns and test if missingness is random. Try it: Change var or group_by to test different variables (e.g., ‘exposure_dd’, ‘ses’).

def missingness_summary(d):
    miss = d.isna().mean().sort_values(ascending=False)
    return pd.DataFrame({"missing_%": (miss*100).round(1), "n_missing": d.isna().sum()})

def test_mar(df, var, group_by):
    if var not in df.columns or group_by not in df.columns:
        return "Invalid column names"
    miss = df[var].isna()
    if df[group_by].dtype == object or pd.api.types.is_categorical_dtype(df[group_by]):
        contingency = pd.crosstab(miss, df[group_by])
        chi2, p = stats.chi2_contingency(contingency)[:2]
        return {"chi2": chi2, "p_value": p, "contingency": contingency}
    else:
        miss_val = df.loc[miss, group_by]
        not_miss_val = df.loc[~miss, group_by]
        t_stat, p = stats.ttest_ind(miss_val.dropna(), not_miss_val.dropna(), equal_var=False)
        return {"t_stat": t_stat, "p_value": p}

miss = missingness_summary(df)
miss.head(10)

# Test missingness
var = MAPPING.get("exposure_biomarker")
group_by = MAPPING.get("outcome")
mar_test = test_mar(df, var, group_by)
print(f"MAR test for {var} by {group_by}:")
print(mar_test)

4 4) Missing data — complete-case vs simple imputation (teaching)
We’ll compare complete-case (CC) analysis to a crude median/mode imputation. This is for teaching only; in practice prefer multiple imputation (not covered here to avoid new dependencies).

vars_model = [OUTCOME, EXPOSURE] + conf
cc = df[vars_model].dropna().copy()
print('CC n =', len(cc))

imp = df[vars_model].copy()
for c in imp.select_dtypes(include=['float64','int64']).columns:
    imp[c] = imp[c].fillna(imp[c].median())
for c in imp.select_dtypes(include=['object','category']).columns:
    md = imp[c].mode(dropna=True)
    if len(md): imp[c] = imp[c].fillna(md.iloc[0])
print('Imputed n =', len(imp) - imp.isna().sum(axis=1).gt(0).sum())

def fit_logit(dat):
    def cat(v):
        return f"C({v})" if (dat[v].dtype=='object' or str(dat[v].dtype).startswith('category')) else v
    rhs = ' + '.join([EXPOSURE] + [cat(v) for v in conf])
    y, X = dmatrices(f'{OUTCOME} ~ ' + rhs, data=dat, return_type='dataframe')
    return sm.Logit(y, X).fit(disp=False)

fit_cc  = fit_logit(cc)
fit_imp = fit_logit(imp)

def tidy_or_table(term, *fits):
    rows = []
    for tag, ft in fits:
        OR = np.exp(ft.params[term])
        lo, hi = np.exp(ft.conf_int().loc[term].values)
        rows.append({'Model': tag, 'OR': round(float(OR),3), '2.5%': round(float(lo),3), '97.5%': round(float(hi),3)})
    return pd.DataFrame(rows)

tidy_or_table(EXPOSURE, ('Complete-case', fit_cc), ('Median/mode impute', fit_imp))

Interpretation - Differences between CC and imputed estimates indicate missingness sensitivity. If MAR is plausible and the imputation model is poor, bias can remain. - MNAR (e.g., sicker participants underreport diet) cannot be diagnosed from observed data alone — acknowledge and explore bounds if critical to inference.

3 3) Energy scaling
Dietary components tend to correlate with total energy. Normalise selected intakes per 1000 kcal to reduce confounding by energy intake (a simple density approach; not universally appropriate but useful as a teaching baseline).

import numpy as np, pandas as pd
d = df.copy()
eps = 1e-6
if 'energy_kcal' in d:
    for v in ['fruit_veg_g_d','red_meat_g_d','salt_g_d','fibre_g_d','ssb_ml_d']:
        if v in d:
            d[v+'_per_1k'] = d[v] / (d['energy_kcal']+eps) * 1000

# Correlations with energy (raw vs density) — orientation
corrs = {}
for v in ['fruit_veg_g_d','red_meat_g_d','salt_g_d']:
    if v in d:
        cr = d[[v,'energy_kcal']].corr().iloc[0,1]
        dv = v+'_per_1k'
        cr_den = d[[dv,'energy_kcal']].corr().iloc[0,1] if dv in d else np.nan
        corrs[v] = {'raw_vs_energy': round(cr,3), 'density_vs_energy': round(cr_den,3)}
pd.DataFrame(corrs).T

Interpretation prompt: Do density adjustments reduce the apparent energy correlation as expected? When might density scaling be inappropriate (e.g., if energy is on the causal pathway for your question)?

